# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ Management API endpoint
rabbitmq_url = "amqp://localhost:15672"

# Credentials for RabbitMQ Management API
username = "admin"
password = "password"

# Define virtual hosts and their settings
vhosts = {
    "app1": {"users": ["user1"], "queues": ["queue1"]},
    "app2": {"users": ["user2"], "queues": ["queue2"]},
}

# Create virtual hosts
for vhost, config in vhosts.items():
    response = requests.put(
        f"{rabbitmq_url}/vhosts/{vhost}",
        auth=(username, password),
        json={},
    )

# Create users
for vhost, config in vhosts.items():
    for user in config["users"]:
        response = requests.put(
            f"{rabbitmq_url}/users/{user}",
            auth=(username, password),
            json={"password": "password"},
        )

# Grant permissions for queues
for vhost, config in vhosts.items():
    for user in config["users"]:
        for queue in config["queues"]:
            response = requests.put(
                f"{rabbitmq_url}/permissions/{user}/{vhost}/{queue}",
                auth=(username, password),
                json={"configure": ".*", "write": ".*", "read": ".*"},
            )